#include <iostream>
#include <cmath>
#include <iomanip>
using namespace std;

int main()
{
	string a;
	char b;
	getline(cin,a);
	for(int i=0;i<a.length();i++){
		b=a[i];
		if(a[i]=='a') b='z';
		if(a[i]>'a'&&a[i]<='z') b--;
		if(a[i]=='A') b='Z';
		if(a[i]>'A'&&a[i]<='Z') b--;
		cout<<b;
	}	
	return 0;
}
